-- Band Operations Toolkit: the artist-facing daily operating layer.
create table public.setlists (id uuid primary key default gen_random_uuid(), artist_id uuid not null references public.artists(id) on delete cascade, name text not null, description text, deal_id uuid references public.deals(id) on delete set null, target_duration_minutes integer, estimated_duration_minutes integer, is_template boolean not null default false, status text not null default 'draft' check (status in ('draft','finalized','performed','archived')), transition_notes text, encore text[] not null default '{}', created_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.setlist_items (id uuid primary key default gen_random_uuid(), setlist_id uuid not null references public.setlists(id) on delete cascade, position integer not null, song_title text not null, song_key text, tempo_bpm integer, duration_seconds integer, notes text, lead_vocalist text, is_opener boolean not null default false, is_closer boolean not null default false, set_break_before boolean not null default false, created_at timestamptz not null default now(), unique(setlist_id, position));
create table public.practices (id uuid primary key default gen_random_uuid(), artist_id uuid not null references public.artists(id) on delete cascade, title text not null default 'Practice', practice_date date not null, start_time time not null, end_time time not null, location text not null default 'Studio', focus_type text check (focus_type in ('full_set','new_material','specific_songs','pre_show_prep','songwriting','improvisation','recording_prep','general')), setlist_id uuid references public.setlists(id) on delete set null, songs_to_practice text[] not null default '{}', notes text, expected_attendees text[] not null default '{}', confirmed_attendees text[] not null default '{}', declined_attendees text[] not null default '{}', status text not null default 'scheduled' check (status in ('scheduled','completed','cancelled','no_show')), completed_notes text, created_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.show_run_sheets (id uuid primary key default gen_random_uuid(), deal_id uuid references public.deals(id) on delete cascade, artist_id uuid not null references public.artists(id) on delete cascade, venue_address text, venue_phone text, parking_instructions text, load_in_time time, soundcheck_time time, doors_open_time time, set_start_time time, set_duration_minutes integer, set_end_time time, curfew_time time, backline_provided text[] not null default '{}', band_brings text[] not null default '{}', stage_dimensions text, payment_method text, payment_contact text, event_bandsintown_url text, venue_instagram text, hashtag text[] not null default '{}', promo_assets_ready boolean not null default false, venue_day_of_contact text, venue_day_of_phone text, manager_day_of_contact text, load_out_instructions text, settlement_notes text, status text not null default 'draft' check (status in ('draft','confirmed','day_of','completed','cancelled')), created_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.meetings (id uuid primary key default gen_random_uuid(), title text not null, meeting_type text not null check (meeting_type in ('band_planning','pre_show_prep','songwriting_session','production_review','interview','press_call','strategy_meeting','label_meeting','other')), scheduled_date date not null, start_time time not null, end_time time, format text not null check (format in ('in_person','zoom','phone','hybrid')), location text, meeting_url text, attendee_profiles uuid[] not null default '{}', attendee_externals text[] not null default '{}', agenda text[] not null default '{}', notes text, action_items text[] not null default '{}', status text not null default 'scheduled' check (status in ('scheduled','in_progress','completed','cancelled')), artist_id uuid references public.artists(id) on delete set null, project_id uuid references public.projects(id) on delete set null, created_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.stage_plots (id uuid primary key default gen_random_uuid(), artist_id uuid not null references public.artists(id) on delete cascade, name text not null default 'Default Stage Plot', inputs jsonb not null default '[]'::jsonb, stage_layout text, member_positions jsonb not null default '[]'::jsonb, power_requirements text, special_needs text, plot_diagram_url text, input_list_pdf_url text, is_active boolean not null default true, version integer not null default 1, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.promo_materials (id uuid primary key default gen_random_uuid(), artist_id uuid not null references public.artists(id) on delete cascade, deal_id uuid references public.deals(id) on delete set null, material_type text not null check (material_type in ('poster','social_post','story','video_teaser','epk','press_photo','ticket_link','event_page','spotify_canvas','facebook_event','instagram_post')), title text not null, file_url text, thumbnail_url text, external_url text, platform text, dimensions text, status text not null default 'needed' check (status in ('needed','in_progress','ready','published','expired')), due_date date, share_link text, download_count integer not null default 0, notes text, created_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.gear_inventory (id uuid primary key default gen_random_uuid(), artist_id uuid not null references public.artists(id) on delete cascade, item_name text not null, category text not null check (category in ('guitar','bass','drums','keys','vocals','amp','pedal','cable','mic','stand','di_box','misc','merch')), brand text, model text, serial_number text, owner text, condition text not null default 'good' check (condition in ('new','excellent','good','fair','broken','lost')), needs_repair boolean not null default false, repair_notes text, estimated_value_cents bigint, last_used_date date, notes text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());

create index practices_artist_date_idx on public.practices(artist_id, practice_date); create index setlists_artist_idx on public.setlists(artist_id, status); create index run_sheets_artist_idx on public.show_run_sheets(artist_id, status); create index meetings_artist_date_idx on public.meetings(artist_id, scheduled_date); create index promo_artist_status_idx on public.promo_materials(artist_id, status); create index gear_artist_category_idx on public.gear_inventory(artist_id, category);
create trigger setlists_updated_at before update on public.setlists for each row execute function public.set_updated_at(); create trigger practices_updated_at before update on public.practices for each row execute function public.set_updated_at(); create trigger show_run_sheets_updated_at before update on public.show_run_sheets for each row execute function public.set_updated_at(); create trigger meetings_updated_at before update on public.meetings for each row execute function public.set_updated_at(); create trigger stage_plots_updated_at before update on public.stage_plots for each row execute function public.set_updated_at(); create trigger promo_materials_updated_at before update on public.promo_materials for each row execute function public.set_updated_at(); create trigger gear_inventory_updated_at before update on public.gear_inventory for each row execute function public.set_updated_at();
alter table public.setlists enable row level security; alter table public.setlist_items enable row level security; alter table public.practices enable row level security; alter table public.show_run_sheets enable row level security; alter table public.meetings enable row level security; alter table public.stage_plots enable row level security; alter table public.promo_materials enable row level security; alter table public.gear_inventory enable row level security;
create policy "setlists operations manages" on public.setlists for all to authenticated using (public.is_operations_team()) with check (public.is_operations_team()); create policy "setlist items operations manages" on public.setlist_items for all to authenticated using (public.is_operations_team()) with check (public.is_operations_team()); create policy "practices operations manages" on public.practices for all to authenticated using (public.is_operations_team()) with check (public.is_operations_team()); create policy "run sheets operations manages" on public.show_run_sheets for all to authenticated using (public.is_operations_team()) with check (public.is_operations_team()); create policy "meetings operations manages" on public.meetings for all to authenticated using (public.is_operations_team()) with check (public.is_operations_team()); create policy "stage plots operations manages" on public.stage_plots for all to authenticated using (public.is_operations_team()) with check (public.is_operations_team()); create policy "promo operations manages" on public.promo_materials for all to authenticated using (public.is_operations_team()) with check (public.is_operations_team()); create policy "gear operations manages" on public.gear_inventory for all to authenticated using (public.is_operations_team()) with check (public.is_operations_team());
grant select, insert, update, delete on public.setlists, public.setlist_items, public.practices, public.show_run_sheets, public.meetings, public.stage_plots, public.promo_materials, public.gear_inventory to authenticated;
